1	package com.coding.assistant.config;
2	
3	import org.springframework.beans.factory.annotation.Value;
4	import org.springframework.context.annotation.Configuration;
5	import org.springframework.web.servlet.config.annotation.CorsRegistry;
6	import org.springframework.web.servlet.config.annotation.ResourceHandlerRegistry;
7	import org.springframework.web.servlet.config.annotation.WebMvcConfigurer;
8	
9	import java.nio.file.Path;
10	import java.nio.file.Paths;
11	
12	@Configuration
13	public class WebConfig implements WebMvcConfigurer {
14	
15	    @Value("${file.upload-dir:./uploads}")
16	    private String uploadDir;
17	
18	    @Override
19	    public void addCorsMappings(CorsRegistry registry) {
20	        registry.addMapping("/**")
21	                .allowedOriginPatterns("*")
22	                .allowedMethods("GET", "POST", "PUT", "DELETE", "OPTIONS", "PATCH")
23	                .allowedHeaders("*")
24	                .allowCredentials(true)
25	                .maxAge(3600);
26	    }
27	
28	    @Override
29	    public void addResourceHandlers(ResourceHandlerRegistry registry) {
30	        Path uploadPath = Paths.get(uploadDir).toAbsolutePath().normalize();
31	        registry.addResourceHandler("/uploads/**")
32	                .addResourceLocations("file:" + uploadPath.toString() + "/");
33	    }
34	}
